from cryptography.hazmat.primitives import serialization
from cryptography.hazmat.primitives.asymmetric import padding
from cryptography.hazmat.primitives import hashes
from cryptography.hazmat.backends import default_backend

class SAMLServiceProvider:
    def __init__(self, idp_metadata_url):
        self.idp_metadata_url = idp_metadata_url
        self.idp_cert = None

    def fetch_idp_metadata(self):
        response = requests.get(self.idp_metadata_url)
        idp_metadata = fromstring(response.content)
        self.idp_cert = idp_metadata.find('.//ds:X509Certificate', namespaces={'ds': 'http://www.w3.org/2000/09/xmldsig#'}).text

    def validate_saml_response(self, saml_response):
        saml_response_decoded = base64.b64decode(saml_response)
        try:
            root = fromstring(saml_response_decoded)
        except ParseError:
            return False

        assertion = root.find('.//Assertion')
        if assertion is None:
            return False

        signature = root.find('.//SignatureValue')
        if signature is None:
            return False

        if not self.verify_signature(saml_response_decoded, signature.text):
            return False

        # Additional checks for SAML response validation can be added here

        return True

    def verify_signature(self, data, signature):
        public_key = serialization.load_pem_public_key(self.idp_cert.encode(), backend=default_backend())
        try:
            public_key.verify(
                base64.b64decode(signature),
                data,
                padding.PKCS1v15(),
                hashes.SHA256()
            )
            return True
        except Exception:
            return False

